"use client";

import React, { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import ComponentCard from "@/components/common/ComponentCard";
import PageBreadcrumb from "@/components/common/PageBreadCrumb";
import { apiFetch } from "@/lib/api";
import { isSuperAdmin } from "@/lib/auth";
import MerchantsTable from "./MerchantsTable";
import MerchantModal from "./MerchantModal";

export type Merchant = {
  id: string;
  business_name_en: string;
  business_name_ar?: string;
  owner_name: string;
  phone_number?: string;
  city?: string;
  address?: string;
  registration_number?: string;
  status?: string;
};

export type MerchantForm = {
  business_name_en: string;
  business_name_ar: string;
  owner_name: string;
  phone_number: string;
  city: string;
  address: string;
  registration_number: string;
  email: string;
  password: string;
  role: string;
};

const emptyForm: MerchantForm = {
  business_name_en: "",
  business_name_ar: "",
  owner_name: "",
  phone_number: "",
  city: "",
  address: "",
  registration_number: "",
  email: "",
  password: "",
  role: "merchant_admin",
};

export default function MerchantsClient() {
  const router = useRouter();

  const [allowed, setAllowed] = useState(false);
  const [loading, setLoading] = useState(true);
  const [merchants, setMerchants] = useState<Merchant[]>([]);
  const [error, setError] = useState("");

  const [page, setPage] = useState(1);
  const pageSize = 15;

  const [isOpen, setIsOpen] = useState(false);
  const [editingMerchant, setEditingMerchant] = useState<Merchant | null>(null);
  const [form, setForm] = useState<MerchantForm>(emptyForm);

  useEffect(() => {
    if (!isSuperAdmin()) {
      router.push("/");
      return;
    }

    setAllowed(true);
    loadMerchants();
  }, [router]);

  async function loadMerchants() {
    try {
      setLoading(true);
      setError("");

      const data = await apiFetch("/admin/merchants");
      setMerchants(data);
    } catch (err: any) {
      setError(err.message || "Failed to load merchants");
    } finally {
      setLoading(false);
    }
  }

  function openAddModal() {
    setEditingMerchant(null);
    setForm(emptyForm);
    setIsOpen(true);
  }

  function openEditModal(merchant: Merchant) {
    setEditingMerchant(merchant);

    setForm({
      business_name_en: merchant.business_name_en || "",
      business_name_ar: merchant.business_name_ar || "",
      owner_name: merchant.owner_name || "",
      phone_number: merchant.phone_number || "",
      city: merchant.city || "",
      address: merchant.address || "",
      registration_number: merchant.registration_number || "",
      email: "",
      password: "",
      role: "merchant_admin",
    });

    setIsOpen(true);
  }

  function closeModal() {
    setIsOpen(false);
    setEditingMerchant(null);
    setForm(emptyForm);
  }

  async function saveMerchant(e: React.FormEvent) {
    e.preventDefault();

    try {
      setError("");

      if (editingMerchant) {
        const updatePayload = {
          business_name_en: form.business_name_en,
          business_name_ar: form.business_name_ar,
          owner_name: form.owner_name,
          phone_number: form.phone_number,
          city: form.city,
          address: form.address,
          registration_number: form.registration_number,
        };

        await apiFetch(`/admin/merchants/${editingMerchant.id}`, {
          method: "PATCH",
          body: JSON.stringify(updatePayload),
        });
      } else {
        await apiFetch("/admin/merchants", {
          method: "POST",
          body: JSON.stringify(form),
        });
      }

      closeModal();
      await loadMerchants();
    } catch (err: any) {
      setError(err.message || "Failed to save merchant");
    }
  }

  async function deleteMerchant(id: string) {
    if (!confirm("Are you sure you want to delete this merchant?")) return;

    try {
      setError("");

      await apiFetch(`/admin/merchants/${id}`, {
        method: "DELETE",
      });

      await loadMerchants();
    } catch (err: any) {
      setError(err.message || "Failed to delete merchant");
    }
  }

  const totalPages = Math.ceil(merchants.length / pageSize);

  const paginatedMerchants = merchants.slice(
    (page - 1) * pageSize,
    page * pageSize
  );

  if (!allowed) {
    return (
      <div className="rounded-lg border border-gray-200 bg-white p-5 text-sm text-gray-500 dark:border-gray-800 dark:bg-white/[0.03] dark:text-gray-400">
        Checking access...
      </div>
    );
  }

  return (
    <div>
      <PageBreadcrumb pageTitle="Merchants" />

      <div className="space-y-6">
        <ComponentCard title="Merchants">
          <div className="mb-5 flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
            <div>
              <h4 className="text-lg font-semibold text-gray-800 dark:text-white/90">
                Merchant Records
              </h4>
              <p className="mt-1 text-sm text-gray-500 dark:text-gray-400">
                View, add, update and delete merchant accounts.
              </p>
            </div>

            <button
              onClick={openAddModal}
              className="inline-flex items-center justify-center rounded-lg bg-brand-500 px-4 py-2.5 text-sm font-medium text-white hover:bg-brand-600"
            >
              Add Merchant
            </button>
          </div>

          {error && (
            <div className="mb-5 rounded-lg border border-error-200 bg-error-50 px-4 py-3 text-sm text-error-700 dark:border-error-500/30 dark:bg-error-500/10 dark:text-error-400">
              {error}
            </div>
          )}

          <MerchantsTable
            merchants={paginatedMerchants}
            loading={loading}
            onEdit={openEditModal}
            onDelete={deleteMerchant}
          />

          <div className="mt-4 flex items-center justify-between">
            <button
              onClick={() => setPage((p) => Math.max(p - 1, 1))}
              disabled={page === 1}
              className="rounded-lg border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
            >
              Previous
            </button>

            <span className="text-sm text-gray-500 dark:text-gray-400">
              Page {page} of {totalPages || 1}
            </span>

            <button
              onClick={() => setPage((p) => Math.min(p + 1, totalPages))}
              disabled={page === totalPages || totalPages === 0}
              className="rounded-lg border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
            >
              Next
            </button>
          </div>
        </ComponentCard>
      </div>

      <MerchantModal
        isOpen={isOpen}
        onClose={closeModal}
        editingMerchant={editingMerchant}
        form={form}
        setForm={setForm}
        onSubmit={saveMerchant}
      />
    </div>
  );
}