"use client";

import React from "react";
import { Modal } from "@/components/ui/modal";
import Button from "@/components/ui/button/Button";
import Input from "@/components/form/input/InputField";
import Label from "@/components/form/Label";
import type { Merchant, MerchantForm } from "./MerchantsClient";

type Props = {
  isOpen: boolean;
  onClose: () => void;
  editingMerchant: Merchant | null;
  form: MerchantForm;
  setForm: React.Dispatch<React.SetStateAction<MerchantForm>>;
  onSubmit: (e: React.FormEvent) => void;
};

const selectClass =
  "h-11 w-full rounded-lg border border-gray-300 bg-transparent px-4 py-2.5 text-sm text-gray-800 shadow-theme-xs focus:border-brand-300 focus:outline-hidden focus:ring-3 focus:ring-brand-500/10 dark:border-gray-700 dark:bg-gray-900 dark:text-white/90";

export default function MerchantModal({
  isOpen,
  onClose,
  editingMerchant,
  form,
  setForm,
  onSubmit,
}: Props) {
  return (
    <Modal isOpen={isOpen} onClose={onClose} className="max-w-[800px] m-4">
      <div className="no-scrollbar relative w-full max-w-[800px] overflow-y-auto rounded-3xl bg-white p-4 dark:bg-gray-900 lg:p-11">
        <div className="px-2 pr-14">
          <h4 className="mb-2 text-2xl font-semibold text-gray-800 dark:text-white/90">
            {editingMerchant ? "Edit Merchant" : "Add Merchant"}
          </h4>

          <p className="mb-6 text-sm text-gray-500 dark:text-gray-400 lg:mb-7">
أدخل معومات الشركة/مزود الخدمة
          </p>
        </div>

        <form
          key={editingMerchant?.id || "new-merchant"}
          onSubmit={onSubmit}
          className="flex flex-col"
        >
          <div className="custom-scrollbar max-h-[520px] overflow-y-auto px-2 pb-3">
            <h5 className="mb-5 text-lg font-medium text-gray-800 dark:text-white/90 lg:mb-6">
              معلومات الشركة
            </h5>
             <div>
                <Label>اسم الشركة</Label>
                <Input
                  type="text"
                  defaultValue={form.business_name_ar}
                  onChange={(e) =>
                    setForm({ ...form, business_name_ar: e.target.value })
                  }
                />
              </div>

           
            <div className="grid grid-cols-1 gap-x-6 gap-y-5 lg:grid-cols-2">
              <div>
                <Label>Business Name English</Label>
                <Input
                  type="text"
                  defaultValue={form.business_name_en}
                  onChange={(e) =>
                    setForm({ ...form, business_name_en: e.target.value })
                  }
                  required
                />
              </div>

          
              <div>
                <Label>المالك</Label>
                <Input
                  type="text"
                  defaultValue={form.owner_name}
                  onChange={(e) =>
                    setForm({ ...form, owner_name: e.target.value })
                  }
                  required
                />
              </div>

              <div>
                <Label>رقم الهاتف</Label>
                <Input
                  type="text"
                  defaultValue={form.phone_number}
                  onChange={(e) =>
                    setForm({ ...form, phone_number: e.target.value })
                  }
                />
              </div>

              <div>
                <Label>المدينة</Label>
                <Input
                  type="text"
                  defaultValue={form.city}
                  onChange={(e) => setForm({ ...form, city: e.target.value })}
                />
              </div>

              <div>
                <Label>العنوان الكامل</Label>
                <Input
                  type="text"
                  defaultValue={form.address}
                  onChange={(e) =>
                    setForm({ ...form, address: e.target.value })
                  }
                />
              </div>

              <div className="lg:col-span-2">
                <Label>رقم التسجيل</Label>
                <Input
                  type="text"
                  defaultValue={form.registration_number}
                  onChange={(e) =>
                    setForm({ ...form, registration_number: e.target.value })
                  }
                />
              </div>
            </div>

            {!editingMerchant && (
              <div className="mt-7">
                <h5 className="mb-5 text-lg font-medium text-gray-800 dark:text-white/90 lg:mb-6">
                  Login Account
                </h5>

                <div className="grid grid-cols-1 gap-x-6 gap-y-5 lg:grid-cols-2">
                  <div>
                    <Label>Login Email</Label>
                    <Input
                      type="email"
                      defaultValue={form.email}
                      onChange={(e) =>
                        setForm({ ...form, email: e.target.value })
                      }
                      required
                    />
                  </div>

                  <div>
                    <Label>Login Password</Label>
                    <Input
                      type="password"
                      defaultValue={form.password}
                      onChange={(e) =>
                        setForm({ ...form, password: e.target.value })
                      }
                      required
                    />
                  </div>

                  <div className="lg:col-span-2">
                    <Label>Role</Label>
                    <select
                      className={selectClass}
                      value={form.role}
                      onChange={(e) =>
                        setForm({ ...form, role: e.target.value })
                      }
                    >
                      <option value="merchant_admin">Merchant Admin</option>
                      <option value="merchant_user">Merchant User</option>
                    </select>
                  </div>
                </div>
              </div>
            )}
          </div>

          <div className="flex items-center gap-3 px-2 mt-6 lg:justify-end">
            <Button size="sm" variant="outline" type="button" onClick={onClose}>
              Close
            </Button>

            <Button size="sm" type="submit">
              {editingMerchant ? "Save Changes" : "Add Merchant"}
            </Button>
          </div>
        </form>
      </div>
    </Modal>
  );
}